var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"허허. 역시 성녀님이십니다. 설마 이렇게 빨리 결과가 나올 줄이야.","JPN":"ほっほ。さすがは聖女様。まさか、こんなにも早く結果が出るとは。","ENG":"Ha ha. You are, no doubt, the Saintess. I didn't think we would get the results so quickly.","TWN":"呵呵，果然是聖女。沒想到這麼快就會有結果。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"약속대로 신의를 드리겠습니다.","JPN":"お約束どおり、神衣をさしあげましょう。","ENG":"Here are the sacred garments, as promised.","TWN":"按照習俗，這是要給聖女穿的聖衣。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"이 늙은이. 벌써부터 제를 올리는 순간이 기대되는군요.","JPN":"この老人めは今から祭祀を行うその時が楽しみでなりません。","ENG":"I am already excited for the rite.","TWN":"真期待獻祭的那一刻。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"감사합니다. 그런데 구원자님은 어디 계시죠?","JPN":"ありがとうございます。ところで、救世主様はどこに？","ENG":"Thank you. But where might the Savior be?","TWN":"謝謝，不過救贖者大人在哪裡？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"다른 분들도 보이지 않네요. 원래대로라면 진즉 돌아왔을 시간인데.","JPN":"他の方々も見当たらないですね。いつもならすでに戻っていてもいい頃ですが。","ENG":"I don't see the others either. They should be back by now.","TWN":"其他人也沒看到，照理說早該回來了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"흠… 일단 자리에서 기다리고 계시면 어떻겠습니까?","JPN":"ふむ……とりあえず、この場でお待ちになってはいかがですかな？","ENG":"Hmm... You could wait for them at the ritual area.","TWN":"嗯…那麼聖女不如先在這裡稍等片刻，"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"다른 것들은 준비되었으니, 구원자님만 오시면 바로 제를 올릴 수 있을 겁니다.","JPN":"その他のものはすでに準備ができていますから、救世主様さえいらっしゃればすぐ祭祀を行えるでしょう。","ENG":"Everything else is ready, so we should be able to perform the rite as soon as the Savior arrives.","TWN":"其他東西都已經準備妥當，只要救贖者大人一來就可以馬上舉行祭祀。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"네, 알겠습니다.","JPN":"はい、わかりました。","ENG":"Very well.","TWN":"好的，就聽村長的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"WOMAN_MEMORIAL_NULL_A","text":{"KOREA":"세상에. 엄청 아름다우셔요!","JPN":"まあ。とてもお綺麗です！","ENG":"My god, you look beautiful!","TWN":"哇喔，好美喔！"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WOMAN_MEMORIAL_NULL_A","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WOMAN_MEMORIAL_NULL_B","text":{"KOREA":"이런 성녀님이랑 춤을 출 수 있다니. 구원자님이 부러워라~.","JPN":"こんな聖女様と一緒に踊れるなんて。救世主様がうらやましい～","ENG":"I'm jealous that the Savior gets to dance with such a beautiful Saintess!","TWN":"可以和這麼美的聖女一起跳舞，真是羨慕救贖者大人～"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WOMAN_MEMORIAL_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WOMAN_MEMORIAL_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WOMAN_MEMORIAL_NULL_A","text":{"KOREA":"성녀님? 혹시 옷이 마음에 들지 않으시나요?","JPN":"聖女様？　もしかして、服がお気に召しませんか？","ENG":"Saintess? Are the garments not to your liking?","TWN":"聖女？是不喜歡這身衣服嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WOMAN_MEMORIAL_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"아닙니다. 조금 신경 쓰이는 일이 있어서요.","JPN":"いいえ。少し気になることがあって。","ENG":"No, there's just something bothering me.","TWN":"不是，只是有點擔心的事情。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WOMAN_MEMORIAL_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"구원자님이… 약속을 어기실 리 없을 텐데.","JPN":"救世主様が……約束を破るわけがないのに。","ENG":"The Savior... isn't one to break his promise.","TWN":"救贖者大人…不可能不守約的。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"무슨 일이 생기신 건가…?","JPN":"何かあったのかな……？","ENG":"Did something happen to him...?","TWN":"到底發生什麼事…？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"지진?","JPN":"地震？","ENG":"An earthquake?","TWN":"地震？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"WOMAN_MEMORIAL_NULL_A","text":{"KOREA":"아. 별거 아니에요. 어쩌다 한 번씩 이렇게 소란이 나곤 하거든요.","JPN":"あ。大したことじゃありません。時々、こんな風に騒動が起きるんですよ。","ENG":"Ah. It's nothing. This happens once in a while.","TWN":"喔，沒什麼，偶爾會這樣。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_MEMORIAL_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"WOMAN_MEMORIAL_NULL_A","text":{"KOREA":"금방 잠잠해질 테니 너무 걱정 마세요.","JPN":"すぐに治まるはずですから、あまり心配しないでください。","ENG":"Don't worry, it'll become stable in no time.","TWN":"很快就會停的，別擔心。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_MEMORIAL_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"WOMAN_MEMORIAL_NULL_B","text":{"KOREA":"어, 어라? 뭔가 평소보다 심하지 않아?","JPN":"あ、あれ？　何かいつもよりひどくない？","ENG":"H-huh? This feels worse than usual.","TWN":"嗯？怎麼感覺搖得比平時還厲害？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WOMAN_MEMORIAL_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WOMAN_MEMORIAL_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"WOMAN_MEMORIAL_NULL_A","text":{"KOREA":"이상하다? 이런 적은 지금까지 한 번도 없었는데?","JPN":"おかしいわね。今までこんなことは一度もなかったのに。","ENG":"That's odd, it's never done this before.","TWN":"奇怪？以前從來不會這樣的？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WOMAN_MEMORIAL_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WOMAN_MEMORIAL_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"WOMAN_MEMORIAL_NULL_A","text":{"KOREA":"괴수? 저 녀석들이 왜 마을에 있는 거야!","JPN":"怪獣？　どうしてあいつらが村にいるの！？","ENG":"Monsters? Why are there monsters in the village?!","TWN":"是怪獸？為什麼怪獸會在村子裡！"},"stage":{"bg":"CAMP_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_MEMORIAL_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"WOMAN_MEMORIAL_NULL_B","text":{"KOREA":"기사단 분들은? 설마 모두 당하신 건가?","JPN":"騎士団の皆さんは？　まさか、みんなやられてしまったの？","ENG":"What about the knights? Have they fallen to the monsters?!","TWN":"騎士團的人呢？該不會已經全軍覆沒？"},"stage":{"bg":"CAMP_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WOMAN_MEMORIAL_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_02"},{"id":"L49_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"무례하군요. 이깟 놈들에게 기사단이 당했을 리 전무합니다.","JPN":"無礼ですね。この程度の奴らに騎士団がやられるはずがありません。","ENG":"How rude. It is not possible that the knights would've lost to these pests.","TWN":"大膽，騎士團怎麼可能被這些傢伙擊倒。"},"stage":{"bg":"CAMP_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WOMAN_MEMORIAL_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"하지만… 무언가 문제가 있는 건 확실하네요.","JPN":"ですが……何か問題があるのは確かなようですね。","ENG":"However... It is clear that there is some kind of issue present.","TWN":"不過…應該確實有古怪。"},"stage":{"bg":"CAMP_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WOMAN_MEMORIAL_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"두 분은 다른 기사들에게 도움을 요청하시길. 이곳은 제가 맡겠습니다.","JPN":"お二人は、他の騎士に助けを求めてください。こちらは私が対応します。","ENG":"You two should go get help from the other knights. I'll take care of things here.","TWN":"你們二位去請其他騎士來幫忙，這裡交給我。"},"stage":{"bg":"CAMP_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"……괜찮아.","JPN":"……大丈夫。","ENG":"...It's okay.","TWN":"……沒事的。"},"stage":{"bg":"CAMP_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"아무 일도 없을 거야.","JPN":"何事もないはずよ。","ENG":"Everything will be fine.","TWN":"不會有事的。"},"stage":{"bg":"CAMP_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};